import React, { useEffect, useState } from "react";
import axios from "axios";

const Orders = () => {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("ALL");

  useEffect(() => {
    const token = localStorage.getItem("token");
    axios
      .get("http://localhost:3002/allOrders", {
        headers: { Authorization: `Bearer ${token}` },
      })
      .then((res) => setOrders(res.data))
      .catch((err) => console.error("Orders fetch error:", err))
      .finally(() => setLoading(false));
  }, []);

  const filtered =
    filter === "ALL" ? orders : orders.filter((o) => o.mode === filter);

  if (loading) {
    return <div style={{ padding: "20px" }}>Loading orders...</div>;
  }

  if (orders.length === 0) {
    return (
      <div className="orders">
        <div className="no-orders">
          <p>You haven't placed any orders yet</p>
        </div>
      </div>
    );
  }

  return (
    <div style={{ padding: "20px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: "16px", marginBottom: "16px" }}>
        <h3 className="title">Orders ({orders.length})</h3>
        <div style={{ display: "flex", gap: "8px" }}>
          {["ALL", "BUY", "SELL"].map((f) => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              style={{
                padding: "4px 14px",
                border: "1px solid #ddd",
                borderRadius: "4px",
                background: filter === f ? "#387ed1" : "white",
                color: filter === f ? "white" : "#333",
                cursor: "pointer",
                fontWeight: 500,
                fontSize: "0.82rem",
              }}
            >
              {f}
            </button>
          ))}
        </div>
      </div>

      <div className="order-table">
        <table>
          <thead>
            <tr>
              <th>Instrument</th>
              <th>Type</th>
              <th>Qty.</th>
              <th>Price</th>
              <th>Value</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map((order, index) => (
              <tr key={index}>
                <td><strong>{order.name}</strong></td>
                <td>
                  <span
                    style={{
                      background: order.mode === "BUY" ? "#e3f0ff" : "#ffeaea",
                      color: order.mode === "BUY" ? "#1565c0" : "#c62828",
                      padding: "2px 10px",
                      borderRadius: "4px",
                      fontSize: "0.78rem",
                      fontWeight: 600,
                    }}
                  >
                    {order.mode}
                  </span>
                </td>
                <td>{order.qty}</td>
                <td>₹{Number(order.price).toFixed(2)}</td>
                <td>₹{(order.qty * order.price).toFixed(2)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Orders;
